import 'react-awesome-slider/dist/styles.css';
import './index.css'

const Slider = () => (
  <AwesomeSlider>
    <img  className="c-img" data-src="https://imgur.com/sfjg9R8.png" />
    <img className="c-img" data-src="https://imgur.com/p0wdadG.png" />
    <img className="c-img" data-src="https://imgur.com/96OnkX7.png" />
    <div className="c-img" data-src="https://imgur.com/KtGxwnN.png" /> 


  </AwesomeSlider>
);
export default Slider
